// Access global static data
const data = $getWorkflowStaticData('global');

// If no lastSync exists, default to the start of today
if (!data.lastSync) {
  // Use today's date dynamically
  const today = new Date();
  today.setHours(0, 0, 0, 0); // start of today
  data.lastSync = today.toISOString();
}

// Pass lastSync to next node
return [
  {
    lastSync: data.lastSync
  }
];

const data = $getWorkflowStaticData('global');
const lastSync = data.lastSync
  ? new Date(data.lastSync)
  : new Date('2025-01-01T00:00:00Z');

const createdAt = new Date($json.created_at);

// Add a flag but KEEP the order
return [
  {
    ...$json,
    isNewOrder: createdAt > lastSync
  }
];

